effect.shader:
void main() {
    vec2 texelSize = 1.0 / getTexSize(inputImg.size);
    vec2 center = vec2(0.5 + centerPoint.x/500., 0.5 - centerPoint.y/500.);
    vec2 v = acScreenNorm.st - (vec4(center,0.0,1.0) * acLayerToScreen).xy;
    float speed = length(strength / 2.0 / texelSize);
    if(adaptive)
        speed *= length( acLayerNorm.st - center );
    else
        speed *= smoothstep( 0.0, length(texelSize)*5.0, length( acLayerNorm.st - center ));
    int nSamples = int(clamp(speed, 7.01, 100.01));
    vec4 outColor = vec4(0.0);
    vec2 vnorm = normalize(v)*texelSize*speed;
    vec2 offsetScale = vec2(1., 1.);
    if( acScreenSize.y > acScreenSize.x ) {
        offsetScale.x *= acScreenSize.x / acScreenSize.y;
    } else {
        offsetScale.y *= acScreenSize.y / acScreenSize.x;
    }

    vec4 chromas[7];
    chromas[0] = vec4(.2,0,0,1.0);
    chromas[1] = vec4(.3,0,0,1.0);
    chromas[2] = vec4(.5,.3333,0,1.0);
    chromas[3] = vec4(0,.33333,0,1.0);
    chromas[4] = vec4(0,.33333,.5,1.0);
    chromas[5] = vec4(0,0,.3,1.0);
    chromas[6] = vec4(0,0,.2,1.0);

    for(int i=0; i<nSamples; i++ ) {
        vec2 offset = vnorm * (float(i) / float(nSamples) - 0.5);
        offset *= offsetScale;

        float c = min(float(i) * 7.0 / float(nSamples), 6.0);
        float fr = fract(c);
        int cidx = int(c);

        vec4 chroma = mix(chromas[cidx], chromas[cidx+1], fr);

        outColor += texture2DCv(inputImg.texture, acScreenNorm.st-offset)*chroma;
    }
    outColor.a /= float(nSamples);
    outColor.rgb /= float(nSamples)/7.0;
    gl_FragColor = outColor;
}
